// InteractiveMap.jsx
// Right panel — Leaflet map with dynamic markers
import { useEffect, useRef } from 'react';

const CITY_CENTERS = {
  Hyderabad: [17.385,  78.4867],
  Mumbai:    [19.076,  72.8777],
  Delhi:     [28.6139, 77.2090],
  Bangalore: [12.9716, 77.5946],
  Chennai:   [13.0827, 80.2707],
  default:   [20.5937, 78.9629],  // India center
};

export default function InteractiveMap({ listings, categoryColor, hoveredListing, cityFilter }) {
  const mapRef     = useRef(null);
  const instanceRef = useRef(null);
  const markersRef = useRef([]);

  // Init map once
  useEffect(() => {
    if (instanceRef.current) return;
    const L = window.L;
    if (!L) return;

    const center = cityFilter && CITY_CENTERS[cityFilter] ? CITY_CENTERS[cityFilter] : CITY_CENTERS.default;
    const zoom   = cityFilter ? 11 : 5;

    instanceRef.current = L.map(mapRef.current, { zoomControl: true }).setView(center, zoom);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '© OpenStreetMap',
      maxZoom: 19,
    }).addTo(instanceRef.current);
  }, []);

  // Update center when city changes
  useEffect(() => {
    if (!instanceRef.current) return;
    const center = cityFilter && CITY_CENTERS[cityFilter] ? CITY_CENTERS[cityFilter] : CITY_CENTERS.default;
    const zoom   = cityFilter ? 11 : 5;
    instanceRef.current.setView(center, zoom);
  }, [cityFilter]);

  // Update markers when listings change
  useEffect(() => {
    const L = window.L;
    if (!L || !instanceRef.current) return;

    // Remove old markers
    markersRef.current.forEach(m => m.remove());
    markersRef.current = [];

    listings.forEach(item => {
      if (!item.lat || !item.lng) return;

      const isHovered = hoveredListing && hoveredListing.id === item.id;
      const color     = item.availability ? (categoryColor || '#00d4b4') : '#ef4444';

      const icon = L.divIcon({
        className: '',
        html: `<div style="
          background:${color};
          color:#000;
          font-size:${isHovered ? '12px' : '10px'};
          font-weight:700;
          padding:${isHovered ? '5px 10px' : '3px 7px'};
          border-radius:6px;
          white-space:nowrap;
          box-shadow:0 2px 10px ${color}60;
          border:${isHovered ? '2px solid #fff' : 'none'};
          transform:${isHovered ? 'scale(1.1)' : 'scale(1)'};
          transition:all 0.2s;
        ">${item.adType}</div>`,
        iconAnchor: [20, 8],
      });

      const marker = L.marker([item.lat, item.lng], { icon }).addTo(instanceRef.current);

      marker.bindPopup(`
        <div style="min-width:180px;font-family:sans-serif;padding:4px">
          <div style="font-weight:700;font-size:13px;margin-bottom:5px;color:#1a1a2e">${item.title}</div>
          <div style="font-size:11px;color:#666;margin-bottom:3px">📍 ${item.location} · ${item.area}</div>
          <div style="font-size:11px;color:#666;margin-bottom:8px">🏷 ${item.adType}</div>
          <div style="font-weight:700;font-size:16px;color:${color}">₹${item.minSpend.toLocaleString()}</div>
          <div style="font-size:10px;color:${item.availability ? '#16a34a':'#dc2626'};margin-top:4px;font-weight:600">
            ${item.availability ? '● Available' : '● Sold Out'}
          </div>
        </div>
      `);

      if (isHovered) marker.openPopup();
      markersRef.current.push(marker);
    });
  }, [listings, hoveredListing, categoryColor]);

  return (
    <div style={S.wrap}>
      {/* Map legend */}
      <div style={S.legend}>
        <div style={S.legendItem}><span style={{ ...S.dot, background: categoryColor || '#00d4b4' }} />Available</div>
        <div style={S.legendItem}><span style={{ ...S.dot, background: '#ef4444' }} />Sold Out</div>
        <div style={S.legendCount}>{listings.length} locations</div>
      </div>
      <div ref={mapRef} style={S.map} />
    </div>
  );
}

const S = {
  wrap:        { width: 340, display: 'flex', flexDirection: 'column', background: '#0d1525', borderLeft: '1px solid rgba(0,212,180,0.12)', flexShrink: 0 },
  legend:      { padding: '10px 14px', borderBottom: '1px solid rgba(0,212,180,0.1)', display: 'flex', alignItems: 'center', gap: 14, flexShrink: 0 },
  legendItem:  { display: 'flex', alignItems: 'center', gap: 5, fontSize: 11, color: '#8fa3c0' },
  dot:         { width: 8, height: 8, borderRadius: '50%', flexShrink: 0 },
  legendCount: { marginLeft: 'auto', fontSize: 11, color: '#4a6080' },
  map:         { flex: 1 },
};
